program BasicTokens;
{ COR24 BASIC v1 — Token definitions and keyword table.
  This file defines all token byte values and the keyword
  string table used by the tokenizer and detokenizer.

  Eventually merged into the main interpreter program.
  For now, compiles standalone as a self-test. }

const
  { --- Keyword tokens (0x80-0x97) --- }
  TOK_LET    = 128;  { 0x80 }
  TOK_PRINT  = 129;  { 0x81 }
  TOK_INPUT  = 130;  { 0x82 }
  TOK_IF     = 131;  { 0x83 }
  TOK_THEN   = 132;  { 0x84 }
  TOK_GOTO   = 133;  { 0x85 }
  TOK_GOSUB  = 134;  { 0x86 }
  TOK_RETURN = 135;  { 0x87 }
  TOK_FOR    = 136;  { 0x88 }
  TOK_TO     = 137;  { 0x89 }
  TOK_STEP   = 138;  { 0x8A }
  TOK_NEXT   = 139;  { 0x8B }
  TOK_STOP   = 140;  { 0x8C }
  TOK_END    = 141;  { 0x8D }
  TOK_REM    = 142;  { 0x8E }
  TOK_LIST   = 143;  { 0x8F }
  TOK_RUN    = 144;  { 0x90 }
  TOK_NEW    = 145;  { 0x91 }
  TOK_SAVE   = 146;  { 0x92 }
  TOK_LOAD   = 147;  { 0x93 }
  TOK_BYE    = 148;  { 0x94 }
  TOK_PEEK   = 149;  { 0x95 }
  TOK_POKE   = 150;  { 0x96 }
  TOK_ABS    = 151;  { 0x97 }

  NUM_KEYWORDS = 24;
  FIRST_KEYWORD = 128;
  LAST_KEYWORD  = 151;

  { --- Operator tokens (0xA0-0xA9) --- }
  TOK_PLUS   = 160;  { 0xA0  +  }
  TOK_MINUS  = 161;  { 0xA1  -  }
  TOK_STAR   = 162;  { 0xA2  *  }
  TOK_SLASH  = 163;  { 0xA3  /  }
  TOK_EQ     = 164;  { 0xA4  =  }
  TOK_NE     = 165;  { 0xA5  <> }
  TOK_LT     = 166;  { 0xA6  <  }
  TOK_LE     = 167;  { 0xA7  <= }
  TOK_GT     = 168;  { 0xA8  >  }
  TOK_GE     = 169;  { 0xA9  >= }

  { --- Delimiter tokens (0xB0-0xB3) --- }
  TOK_LPAREN = 176;  { 0xB0  (  }
  TOK_RPAREN = 177;  { 0xB1  )  }
  TOK_COMMA  = 178;  { 0xB2  ,  }
  TOK_SEMI   = 179;  { 0xB3  ;  }

  { --- Variable tokens (0xC0-0xD9) --- }
  TOK_VAR_A  = 192;  { 0xC0  A  }
  TOK_VAR_Z  = 217;  { 0xD9  Z  }

  { --- Literal tokens --- }
  TOK_INT    = 224;  { 0xE0  followed by 3-byte big-endian value }
  TOK_STR    = 225;  { 0xE1  followed by length byte then chars }

  { --- End of line --- }
  TOK_EOL    = 0;

  { --- Keyword string table ---
    Stored as a flat char array with fixed-width 8-char entries
    (padded with spaces). This avoids needing an array of strings
    or pointer indirection. }
  KW_WIDTH = 8;

var
  { Keyword names, packed into a flat array: 24 keywords * 8 chars }
  kw_table: array[0..191] of char;
  i: integer;

procedure kw_set(idx: integer; s0, s1, s2, s3, s4, s5, s6, s7: char);
{ Set keyword entry at index idx (0..NUM_KEYWORDS-1).
  Each entry is KW_WIDTH chars, space-padded. }
var base: integer;
begin
  base := idx * KW_WIDTH;
  kw_table[base]     := s0;
  kw_table[base + 1] := s1;
  kw_table[base + 2] := s2;
  kw_table[base + 3] := s3;
  kw_table[base + 4] := s4;
  kw_table[base + 5] := s5;
  kw_table[base + 6] := s6;
  kw_table[base + 7] := s7
end;

procedure init_keywords;
begin
  kw_set( 0, 'L','E','T',' ',' ',' ',' ',' ');
  kw_set( 1, 'P','R','I','N','T',' ',' ',' ');
  kw_set( 2, 'I','N','P','U','T',' ',' ',' ');
  kw_set( 3, 'I','F',' ',' ',' ',' ',' ',' ');
  kw_set( 4, 'T','H','E','N',' ',' ',' ',' ');
  kw_set( 5, 'G','O','T','O',' ',' ',' ',' ');
  kw_set( 6, 'G','O','S','U','B',' ',' ',' ');
  kw_set( 7, 'R','E','T','U','R','N',' ',' ');
  kw_set( 8, 'F','O','R',' ',' ',' ',' ',' ');
  kw_set( 9, 'T','O',' ',' ',' ',' ',' ',' ');
  kw_set(10, 'S','T','E','P',' ',' ',' ',' ');
  kw_set(11, 'N','E','X','T',' ',' ',' ',' ');
  kw_set(12, 'S','T','O','P',' ',' ',' ',' ');
  kw_set(13, 'E','N','D',' ',' ',' ',' ',' ');
  kw_set(14, 'R','E','M',' ',' ',' ',' ',' ');
  kw_set(15, 'L','I','S','T',' ',' ',' ',' ');
  kw_set(16, 'R','U','N',' ',' ',' ',' ',' ');
  kw_set(17, 'N','E','W',' ',' ',' ',' ',' ');
  kw_set(18, 'S','A','V','E',' ',' ',' ',' ');
  kw_set(19, 'L','O','A','D',' ',' ',' ',' ');
  kw_set(20, 'B','Y','E',' ',' ',' ',' ',' ');
  kw_set(21, 'P','E','E','K',' ',' ',' ',' ');
  kw_set(22, 'P','O','K','E',' ',' ',' ',' ');
  kw_set(23, 'A','B','S',' ',' ',' ',' ',' ')
end;

function kw_len(idx: integer): integer;
{ Return the actual length of keyword at index (without trailing spaces) }
var base, len: integer;
begin
  base := idx * KW_WIDTH;
  len := KW_WIDTH;
  while (len > 0) and (kw_table[base + len - 1] = ' ') do
    len := len - 1;
  kw_len := len
end;

function kw_char(idx, pos: integer): char;
{ Return character at position pos of keyword idx }
begin
  kw_char := kw_table[idx * KW_WIDTH + pos]
end;

function is_keyword(tok: integer): boolean;
begin
  is_keyword := (tok >= FIRST_KEYWORD) and (tok <= LAST_KEYWORD)
end;

function is_operator(tok: integer): boolean;
begin
  is_operator := (tok >= TOK_PLUS) and (tok <= TOK_GE)
end;

function is_variable(tok: integer): boolean;
begin
  is_variable := (tok >= TOK_VAR_A) and (tok <= TOK_VAR_Z)
end;

function var_index(tok: integer): integer;
{ Convert variable token to 0-based index (A=0, B=1, ..., Z=25) }
begin
  var_index := tok - TOK_VAR_A
end;

function var_token(idx: integer): integer;
{ Convert 0-based index to variable token }
begin
  var_token := idx + TOK_VAR_A
end;

{ --- Detokenizer --- }

procedure print_keyword(tok: integer);
{ Print the keyword name for a keyword token }
var idx, len, j: integer;
begin
  idx := tok - FIRST_KEYWORD;
  len := kw_len(idx);
  j := 0;
  while j < len do
  begin
    write(kw_char(idx, j));
    j := j + 1
  end
end;

procedure print_operator(tok: integer);
begin
  if tok = TOK_PLUS  then write('+');
  if tok = TOK_MINUS then write('-');
  if tok = TOK_STAR  then write('*');
  if tok = TOK_SLASH then write('/');
  if tok = TOK_EQ    then write('=');
  if tok = TOK_NE    then begin write('<'); write('>') end;
  if tok = TOK_LT    then write('<');
  if tok = TOK_LE    then begin write('<'); write('=') end;
  if tok = TOK_GT    then write('>');
  if tok = TOK_GE    then begin write('>'); write('=') end
end;

procedure print_variable(tok: integer);
var ch: char;
begin
  ch := chr(ord('A') + tok - TOK_VAR_A);
  write(ch)
end;

{ --- Self-test --- }

var
  pass_count, fail_count: integer;

procedure check(ok: boolean; tag: integer);
begin
  if ok then
  begin
    write('PASS ');
    pass_count := pass_count + 1
  end
  else
  begin
    write('FAIL ');
    fail_count := fail_count + 1
  end;
  writeln(tag)
end;

begin
  init_keywords;
  pass_count := 0;
  fail_count := 0;

  { Test 1: Token value ranges }
  check(TOK_LET = 128, 1);
  check(TOK_ABS = 151, 2);
  check(TOK_PLUS = 160, 3);
  check(TOK_GE = 169, 4);
  check(TOK_LPAREN = 176, 5);
  check(TOK_VAR_A = 192, 6);
  check(TOK_INT = 224, 7);
  check(TOK_EOL = 0, 8);

  { Test 2: Keyword lengths }
  check(kw_len(0) = 3, 9);     { LET }
  check(kw_len(1) = 5, 10);    { PRINT }
  check(kw_len(3) = 2, 11);    { IF }
  check(kw_len(7) = 6, 12);    { RETURN }
  check(kw_len(9) = 2, 13);    { TO }

  { Test 3: Keyword characters }
  check(kw_char(0, 0) = 'L', 14);
  check(kw_char(0, 1) = 'E', 15);
  check(kw_char(0, 2) = 'T', 16);
  check(kw_char(1, 0) = 'P', 17);   { PRINT }
  check(kw_char(5, 0) = 'G', 18);   { GOTO }
  check(kw_char(5, 3) = 'O', 19);

  { Test 4: Classification functions }
  check(is_keyword(TOK_LET), 20);
  check(is_keyword(TOK_ABS), 21);
  check(not is_keyword(TOK_PLUS), 22);
  check(not is_keyword(TOK_VAR_A), 23);
  check(is_operator(TOK_PLUS), 24);
  check(is_operator(TOK_GE), 25);
  check(not is_operator(TOK_LET), 26);
  check(is_variable(TOK_VAR_A), 27);
  check(is_variable(TOK_VAR_Z), 28);
  check(not is_variable(TOK_LET), 29);

  { Test 5: Variable index conversion }
  check(var_index(TOK_VAR_A) = 0, 30);
  check(var_index(TOK_VAR_Z) = 25, 31);
  check(var_token(0) = TOK_VAR_A, 32);
  check(var_token(25) = TOK_VAR_Z, 33);

  { Test 6: Print keyword (visual check) }
  write('KW: ');
  print_keyword(TOK_PRINT);
  writeln('');

  write('KW: ');
  print_keyword(TOK_GOSUB);
  writeln('');

  { Test 7: Print operator (visual check) }
  write('OP: ');
  print_operator(TOK_LE);
  writeln('');

  write('OP: ');
  print_operator(TOK_NE);
  writeln('');

  { Test 8: Print variable (visual check) }
  write('VAR: ');
  print_variable(TOK_VAR_A);
  writeln('');

  write('VAR: ');
  print_variable(TOK_VAR_Z);
  writeln('');

  { Summary }
  write('Tests: ');
  writeln(pass_count + fail_count);
  write('Passed: ');
  writeln(pass_count);
  write('Failed: ');
  writeln(fail_count);
  if fail_count = 0 then
    writeln('ALL PASS')
  else
    writeln('FAILURES')
end.

