program BasicTokens;
{ COR24 BASIC v1 — Token definitions, keyword table, and detokenizer.
  Compiles standalone as a self-test; will be merged into the full
  interpreter program. }

const
  { Keyword tokens (0x80-0x97) }
  TOK_LET    = 128;
  TOK_PRINT  = 129;
  TOK_INPUT  = 130;
  TOK_IF     = 131;
  TOK_THEN   = 132;
  TOK_GOTO   = 133;
  TOK_GOSUB  = 134;
  TOK_RETURN = 135;
  TOK_FOR    = 136;
  TOK_TO     = 137;
  TOK_STEP   = 138;
  TOK_NEXT   = 139;
  TOK_STOP   = 140;
  TOK_END    = 141;
  TOK_REM    = 142;
  TOK_LIST   = 143;
  TOK_RUN    = 144;
  TOK_NEW    = 145;
  TOK_SAVE   = 146;
  TOK_LOAD   = 147;
  TOK_BYE    = 148;
  TOK_PEEK   = 149;
  TOK_POKE   = 150;
  TOK_ABS    = 151;
  NUM_KEYWORDS  = 24;
  FIRST_KEYWORD = 128;
  LAST_KEYWORD  = 151;

  { Operator tokens (0xA0-0xA9) }
  TOK_PLUS   = 160;
  TOK_MINUS  = 161;
  TOK_STAR   = 162;
  TOK_SLASH  = 163;
  TOK_EQ     = 164;
  TOK_NE     = 165;
  TOK_LT     = 166;
  TOK_LE     = 167;
  TOK_GT     = 168;
  TOK_GE     = 169;

  { Delimiter tokens (0xB0-0xB3) }
  TOK_LPAREN = 176;
  TOK_RPAREN = 177;
  TOK_COMMA  = 178;
  TOK_SEMI   = 179;

  { Variable tokens (0xC0-0xD9) }
  TOK_VAR_A  = 192;
  TOK_VAR_Z  = 217;

  { Literal tokens }
  TOK_INT    = 224;
  TOK_STR    = 225;

  { End of line }
  TOK_EOL    = 0;

  { Keyword table: flat array, 8 chars per entry }
  KW_WIDTH = 8;

var
  kw_table: array[0..191] of char;

{ --- Keyword table management --- }

procedure kw_set(idx: integer; s0, s1, s2, s3, s4, s5, s6, s7: char);
var base: integer;
begin
  base := idx * KW_WIDTH;
  kw_table[base]     := s0;
  kw_table[base + 1] := s1;
  kw_table[base + 2] := s2;
  kw_table[base + 3] := s3;
  kw_table[base + 4] := s4;
  kw_table[base + 5] := s5;
  kw_table[base + 6] := s6;
  kw_table[base + 7] := s7
end;

procedure init_keywords;
begin
  kw_set( 0, 'L','E','T',' ',' ',' ',' ',' ');
  kw_set( 1, 'P','R','I','N','T',' ',' ',' ');
  kw_set( 2, 'I','N','P','U','T',' ',' ',' ');
  kw_set( 3, 'I','F',' ',' ',' ',' ',' ',' ');
  kw_set( 4, 'T','H','E','N',' ',' ',' ',' ');
  kw_set( 5, 'G','O','T','O',' ',' ',' ',' ');
  kw_set( 6, 'G','O','S','U','B',' ',' ',' ');
  kw_set( 7, 'R','E','T','U','R','N',' ',' ');
  kw_set( 8, 'F','O','R',' ',' ',' ',' ',' ');
  kw_set( 9, 'T','O',' ',' ',' ',' ',' ',' ');
  kw_set(10, 'S','T','E','P',' ',' ',' ',' ');
  kw_set(11, 'N','E','X','T',' ',' ',' ',' ');
  kw_set(12, 'S','T','O','P',' ',' ',' ',' ');
  kw_set(13, 'E','N','D',' ',' ',' ',' ',' ');
  kw_set(14, 'R','E','M',' ',' ',' ',' ',' ');
  kw_set(15, 'L','I','S','T',' ',' ',' ',' ');
  kw_set(16, 'R','U','N',' ',' ',' ',' ',' ');
  kw_set(17, 'N','E','W',' ',' ',' ',' ',' ');
  kw_set(18, 'S','A','V','E',' ',' ',' ',' ');
  kw_set(19, 'L','O','A','D',' ',' ',' ',' ');
  kw_set(20, 'B','Y','E',' ',' ',' ',' ',' ');
  kw_set(21, 'P','E','E','K',' ',' ',' ',' ');
  kw_set(22, 'P','O','K','E',' ',' ',' ',' ');
  kw_set(23, 'A','B','S',' ',' ',' ',' ',' ')
end;

function kw_len(idx: integer): integer;
var base, len: integer;
begin
  base := idx * KW_WIDTH;
  len := KW_WIDTH;
  while (len > 0) and (kw_table[base + len - 1] = ' ') do
    len := len - 1;
  kw_len := len
end;

function kw_char(idx, pos: integer): char;
begin
  kw_char := kw_table[idx * KW_WIDTH + pos]
end;

{ --- Token classification --- }

function is_keyword(tok: integer): boolean;
begin
  is_keyword := (tok >= FIRST_KEYWORD) and (tok <= LAST_KEYWORD)
end;

function is_operator(tok: integer): boolean;
begin
  is_operator := (tok >= TOK_PLUS) and (tok <= TOK_GE)
end;

function is_variable(tok: integer): boolean;
begin
  is_variable := (tok >= TOK_VAR_A) and (tok <= TOK_VAR_Z)
end;

function var_index(tok: integer): integer;
begin
  var_index := tok - TOK_VAR_A
end;

function var_token(idx: integer): integer;
begin
  var_token := idx + TOK_VAR_A
end;

{ --- Detokenizer --- }

procedure print_keyword(tok: integer);
var idx, len, j: integer;
begin
  idx := tok - FIRST_KEYWORD;
  len := kw_len(idx);
  j := 0;
  while j < len do
  begin
    write(kw_char(idx, j));
    j := j + 1
  end
end;

procedure print_operator(tok: integer);
begin
  if tok = TOK_PLUS  then write('+');
  if tok = TOK_MINUS then write('-');
  if tok = TOK_STAR  then write('*');
