  write('OP: '); print_operator(TOK_LE); writeln('');
  write('OP: '); print_operator(TOK_NE); writeln('');
  write('VAR: '); print_variable(TOK_VAR_A); writeln('');
  write('VAR: '); print_variable(TOK_VAR_Z); writeln('');

