var idx, len, j: integer;
begin
  idx := tok - FIRST_KEYWORD; len := kw_len(idx); j := 0;
  while j < len do begin write(kw_char(idx, j)); j := j + 1 end
end;
procedure print_operator(tok: integer);
begin
  if tok = TOK_PLUS then write('+');
  if tok = 161 then write('-'); if tok = 162 then write('*');
  if tok = 163 then write('/'); if tok = 164 then write('=');
  if tok = 165 then begin write('<'); write('>') end;
  if tok = 166 then write('<');
  if tok = 167 then begin write('<'); write('=') end;
  if tok = 168 then write('>');
  if tok = TOK_GE then begin write('>'); write('=') end
end;
procedure print_variable(tok: integer);
var ch: char;
