program BasicLex;
{ COR24 BASIC v1 — Tokenizer.
  Converts a line of BASIC text into a byte token sequence.
  Standalone self-test; will merge into the full interpreter. }

const
  FIRST_KEYWORD = 128;
  LAST_KEYWORD  = 151;
  TOK_PLUS  = 160;
  TOK_GE    = 169;
  TOK_VAR_A = 192;
  TOK_VAR_Z = 217;
  TOK_INT   = 224;
  TOK_STR   = 225;
  KW_WIDTH  = 8;
  NUM_KW    = 24;
  MAX_LINE  = 80;
  MAX_TOK   = 128;

var
  kw_table: array[0..191] of char;
  { Input line }
  line_buf: array[0..79] of char;
  line_len: integer;
  line_pos: integer;
  { Token output }
  tok_buf: array[0..127] of integer;
  tok_len: integer;
  { Parsed line number (-1 = none) }
  tok_line_num: integer;

{ --- Keyword table (from basic_tokens) --- }

procedure kw_set(idx: integer; s0, s1, s2, s3, s4, s5, s6, s7: char);
var base: integer;
begin
  base := idx * KW_WIDTH;
  kw_table[base]     := s0;
  kw_table[base + 1] := s1;
  kw_table[base + 2] := s2;
  kw_table[base + 3] := s3;
  kw_table[base + 4] := s4;
  kw_table[base + 5] := s5;
  kw_table[base + 6] := s6;
  kw_table[base + 7] := s7
end;

procedure init_keywords;
begin
  kw_set( 0, 'L','E','T',' ',' ',' ',' ',' ');
  kw_set( 1, 'P','R','I','N','T',' ',' ',' ');
  kw_set( 2, 'I','N','P','U','T',' ',' ',' ');
  kw_set( 3, 'I','F',' ',' ',' ',' ',' ',' ');
  kw_set( 4, 'T','H','E','N',' ',' ',' ',' ');
  kw_set( 5, 'G','O','T','O',' ',' ',' ',' ');
  kw_set( 6, 'G','O','S','U','B',' ',' ',' ');
  kw_set( 7, 'R','E','T','U','R','N',' ',' ');
  kw_set( 8, 'F','O','R',' ',' ',' ',' ',' ');
  kw_set( 9, 'T','O',' ',' ',' ',' ',' ',' ');
  kw_set(10, 'S','T','E','P',' ',' ',' ',' ');
  kw_set(11, 'N','E','X','T',' ',' ',' ',' ');
  kw_set(12, 'S','T','O','P',' ',' ',' ',' ');
  kw_set(13, 'E','N','D',' ',' ',' ',' ',' ');
  kw_set(14, 'R','E','M',' ',' ',' ',' ',' ');
  kw_set(15, 'L','I','S','T',' ',' ',' ',' ');
  kw_set(16, 'R','U','N',' ',' ',' ',' ',' ');
  kw_set(17, 'N','E','W',' ',' ',' ',' ',' ');
  kw_set(18, 'S','A','V','E',' ',' ',' ',' ');
  kw_set(19, 'L','O','A','D',' ',' ',' ',' ');
  kw_set(20, 'B','Y','E',' ',' ',' ',' ',' ');
  kw_set(21, 'P','E','E','K',' ',' ',' ',' ');
  kw_set(22, 'P','O','K','E',' ',' ',' ',' ');
  kw_set(23, 'A','B','S',' ',' ',' ',' ',' ')
end;

function kw_len(idx: integer): integer;
var base, len: integer;
begin
  base := idx * KW_WIDTH;
  len := KW_WIDTH;
  while (len > 0) and (kw_table[base + len - 1] = ' ') do
    len := len - 1;
  kw_len := len
end;

{ --- Character helpers --- }

function upcase(ch: char): char;
begin
  if (ch >= 'a') and (ch <= 'z') then
    upcase := chr(ord(ch) - 32)
  else
    upcase := ch
end;

function is_digit(ch: char): boolean;
begin
  is_digit := (ch >= '0') and (ch <= '9')
end;

function is_letter(ch: char): boolean;
var uc: char;
begin
  uc := upcase(ch);
  is_letter := (uc >= 'A') and (uc <= 'Z')
end;

function is_space(ch: char): boolean;
begin
  is_space := (ch = ' ') or (ch = chr(9))
end;

{ --- Tokenizer core --- }

procedure emit(val: integer);
begin
  if tok_len < MAX_TOK then
  begin
    tok_buf[tok_len] := val;
    tok_len := tok_len + 1
  end
end;

function peek_char: char;
begin
  if line_pos < line_len then
    peek_char := line_buf[line_pos]
  else
    peek_char := chr(0)
end;

function next_char: char;
var ch: char;
begin
  ch := peek_char;
  if line_pos < line_len then
    line_pos := line_pos + 1;
  next_char := ch
end;

procedure skip_spaces;
begin
  while (line_pos < line_len) and is_space(line_buf[line_pos]) do
    line_pos := line_pos + 1
end;

function parse_integer: integer;
var n: integer;
begin
  n := 0;
  while (line_pos < line_len) and is_digit(line_buf[line_pos]) do
  begin
    n := n * 10 + (ord(line_buf[line_pos]) - ord('0'));
    line_pos := line_pos + 1
  end;
  parse_integer := n
end;

function try_keyword: integer;
{ Try to match a keyword at current position. Returns keyword index
  (0..NUM_KW-1) or -1 if no match. Uses longest match. }
var
  best, best_len: integer;
  ki, kl, j: integer;
  match: boolean;
  uc: char;
begin
  best := -1;
  best_len := 0;
  ki := 0;
  while ki < NUM_KW do
  begin
    kl := kw_len(ki);
    if (kl > best_len) and (line_pos + kl <= line_len) then
    begin
      match := true;
      j := 0;
      while match and (j < kl) do
      begin
        uc := upcase(line_buf[line_pos + j]);
        if uc <> kw_table[ki * KW_WIDTH + j] then
          match := false;
        j := j + 1
      end;
      { Keyword must not be followed by a letter or digit }
      if match and (line_pos + kl < line_len) then
      begin
        uc := upcase(line_buf[line_pos + kl]);
        if is_letter(uc) or is_digit(uc) then
          match := false
      end;
      if match then
      begin
        best := ki;
        best_len := kl
      end
    end;
    ki := ki + 1
  end;
  if best >= 0 then
    line_pos := line_pos + best_len;
  try_keyword := best
end;

procedure tokenize;
{ Tokenize line_buf[0..line_len-1] into tok_buf.
  Sets tok_line_num (-1 if no line number). }
var
  ch: char;
  ki, n: integer;
begin
  tok_len := 0;
  line_pos := 0;
  tok_line_num := -1;

  skip_spaces;

  { Parse optional line number }
  if (line_pos < line_len) and is_digit(line_buf[line_pos]) then
  begin
    tok_line_num := parse_integer;
    skip_spaces
  end;

  { Tokenize remaining }
  while line_pos < line_len do
  begin
    skip_spaces;
    if line_pos >= line_len then
    begin
      { done }
    end
    else
    begin
      ch := line_buf[line_pos];

      { Try keyword match first }
      ki := try_keyword;
      if ki >= 0 then
      begin
        emit(FIRST_KEYWORD + ki);
        { REM: rest of line is a string token }
        if ki = 14 then
        begin
          emit(TOK_STR);
          n := line_len - line_pos;
          emit(n);
          while line_pos < line_len do
          begin
            emit(ord(line_buf[line_pos]));
            line_pos := line_pos + 1
          end
        end
      end
      { String literal }
      else if ch = '"' then
      begin
        line_pos := line_pos + 1;
        emit(TOK_STR);
        n := tok_len;
        emit(0);  { placeholder for length }
        ki := 0;
        while (line_pos < line_len) and (line_buf[line_pos] <> '"') do
        begin
          emit(ord(line_buf[line_pos]));
          line_pos := line_pos + 1;
          ki := ki + 1
        end;
        tok_buf[n] := ki;  { patch length }
        if (line_pos < line_len) and (line_buf[line_pos] = '"') then
          line_pos := line_pos + 1
      end
      { Integer literal }
      else if is_digit(ch) then
      begin
        n := parse_integer;
        emit(TOK_INT);
        emit((n div 65536) mod 256);
        emit((n div 256) mod 256);
        emit(n mod 256)
      end
      { Variable (single letter A-Z) }
      else if is_letter(ch) then
      begin
        emit(TOK_VAR_A + ord(upcase(ch)) - ord('A'));
        line_pos := line_pos + 1
      end
      { Two-char operators }
      else if (ch = '<') and (line_pos + 1 < line_len) and (line_buf[line_pos + 1] = '>') then
      begin emit(TOK_PLUS + 5); line_pos := line_pos + 2 end
      else if (ch = '<') and (line_pos + 1 < line_len) and (line_buf[line_pos + 1] = '=') then
      begin emit(TOK_PLUS + 7); line_pos := line_pos + 2 end
      else if (ch = '>') and (line_pos + 1 < line_len) and (line_buf[line_pos + 1] = '=') then
      begin emit(TOK_GE); line_pos := line_pos + 2 end
      { Single-char operators }
      else if ch = '+' then begin emit(TOK_PLUS);     line_pos := line_pos + 1 end
      else if ch = '-' then begin emit(TOK_PLUS + 1); line_pos := line_pos + 1 end
      else if ch = '*' then begin emit(TOK_PLUS + 2); line_pos := line_pos + 1 end
      else if ch = '/' then begin emit(TOK_PLUS + 3); line_pos := line_pos + 1 end
      else if ch = '=' then begin emit(TOK_PLUS + 4); line_pos := line_pos + 1 end
      else if ch = '<' then begin emit(TOK_PLUS + 6); line_pos := line_pos + 1 end
      else if ch = '>' then begin emit(TOK_PLUS + 8); line_pos := line_pos + 1 end
      { Delimiters }
      else if ch = '(' then begin emit(176); line_pos := line_pos + 1 end
      else if ch = ')' then begin emit(177); line_pos := line_pos + 1 end
      else if ch = ',' then begin emit(178); line_pos := line_pos + 1 end
      else if ch = ';' then begin emit(179); line_pos := line_pos + 1 end
      { Unknown character: skip }
      else
        line_pos := line_pos + 1
    end
  end;

  emit(0)  { TOK_EOL }
end;

{ --- Test helpers --- }

procedure set_line(s0, s1, s2, s3, s4, s5, s6, s7, s8, s9,
                   s10, s11, s12, s13, s14, s15: char; len: integer);
{ Set line_buf from up to 16 chars. Caller sets line_len. }
begin
  line_len := len;
  if len > 0  then line_buf[0]  := s0;
  if len > 1  then line_buf[1]  := s1;
  if len > 2  then line_buf[2]  := s2;
  if len > 3  then line_buf[3]  := s3;
  if len > 4  then line_buf[4]  := s4;
  if len > 5  then line_buf[5]  := s5;
  if len > 6  then line_buf[6]  := s6;
  if len > 7  then line_buf[7]  := s7;
  if len > 8  then line_buf[8]  := s8;
  if len > 9  then line_buf[9]  := s9;
  if len > 10 then line_buf[10] := s10;
  if len > 11 then line_buf[11] := s11;
  if len > 12 then line_buf[12] := s12;
  if len > 13 then line_buf[13] := s13;
  if len > 14 then line_buf[14] := s14;
  if len > 15 then line_buf[15] := s15
end;

var
  fail: integer;
  i: integer;

procedure check(ok: boolean; id: integer);
begin
  if ok then write('P') else begin write('F'); fail := fail + 1 end;
  writeln(id)
end;

begin
  init_keywords;
  fail := 0;

  { Test 1: PRINT keyword }
  { "PRINT" = 5 chars }
  set_line('P','R','I','N','T',' ',' ',' ',' ',' ',' ',' ',' ',' ',' ',' ', 5);
  tokenize;
  check(tok_line_num = -1, 1);
  check(tok_buf[0] = 129, 2);  { TOK_PRINT = 0x81 = 129 }
  check(tok_buf[1] = 0, 3);    { TOK_EOL }

  { Test 2: Line number + keyword }
  { "10 END" = 6 chars }
  set_line('1','0',' ','E','N','D',' ',' ',' ',' ',' ',' ',' ',' ',' ',' ', 6);
  tokenize;
  check(tok_line_num = 10, 4);
  check(tok_buf[0] = 141, 5);  { TOK_END = 0x8D = 141 }
  check(tok_buf[1] = 0, 6);

  { Test 3: Variable assignment "LET A=5" = 7 chars }
  set_line('L','E','T',' ','A','=','5',' ',' ',' ',' ',' ',' ',' ',' ',' ', 7);
  tokenize;
  check(tok_buf[0] = 128, 7);  { TOK_LET }
  check(tok_buf[1] = 192, 8);  { TOK_VAR_A }
  check(tok_buf[2] = 164, 9);  { TOK_EQ = 0xA4 = 164 }
  check(tok_buf[3] = 224, 10); { TOK_INT }
  check(tok_buf[6] = 5, 11);   { low byte of 5 }

  { Test 4: Operators "<=" ">=" "<>" }
  set_line('<','=','>','=','<','>',' ',' ',' ',' ',' ',' ',' ',' ',' ',' ', 6);
  tokenize;
  check(tok_buf[0] = 167, 12); { TOK_LE }
  check(tok_buf[1] = 169, 13); { TOK_GE }
  check(tok_buf[2] = 165, 14); { TOK_NE }

  { Test 5: String "PRINT "HI"" }
  { P R I N T   " H I " = 10 chars }
  set_line('P','R','I','N','T',' ','"','H','I','"',' ',' ',' ',' ',' ',' ', 10);
  tokenize;
  check(tok_buf[0] = 129, 15);     { PRINT }
  check(tok_buf[1] = 225, 16);     { TOK_STR }
  check(tok_buf[2] = 2, 17);       { length = 2 }
  check(tok_buf[3] = ord('H'), 18);
  check(tok_buf[4] = ord('I'), 19);
  check(tok_buf[5] = 0, 20);       { EOL }

  { Test 6: Case insensitivity "print" }
  set_line('p','r','i','n','t',' ',' ',' ',' ',' ',' ',' ',' ',' ',' ',' ', 5);
  tokenize;
  check(tok_buf[0] = 129, 21); { PRINT }

  { Test 7: Delimiters "A,(B)" }
  set_line('A',',','(','B',')',' ',' ',' ',' ',' ',' ',' ',' ',' ',' ',' ', 5);
  tokenize;
  check(tok_buf[0] = 192, 22); { VAR A }
  check(tok_buf[1] = 178, 23); { COMMA }
  check(tok_buf[2] = 176, 24); { LPAREN }
  check(tok_buf[3] = 193, 25); { VAR B }
  check(tok_buf[4] = 177, 26); { RPAREN }

  writeln(fail)
end.

