      while match and (j < kl) do
      begin
        uc := upcase(line_buf[line_pos + j]);
        if uc <> kw_table[ki * KW_WIDTH + j] then
          match := false;
        j := j + 1
      end;
      { Keyword must not be followed by a letter or digit }
      if match and (line_pos + kl < line_len) then
      begin
        uc := upcase(line_buf[line_pos + kl]);
        if is_letter(uc) or is_digit(uc) then
          match := false
      end;
      if match then
      begin
        best := ki;
        best_len := kl
      end
    end;
    ki := ki + 1
  end;
  if best >= 0 then
    line_pos := line_pos + best_len;
  try_keyword := best
end;

procedure tokenize;
{ Tokenize line_buf[0..line_len-1] into tok_buf.
  Sets tok_line_num (-1 if no line number). }
var
  ch: char;
  ki, n: integer;
begin
  tok_len := 0;
  line_pos := 0;
  tok_line_num := -1;

  skip_spaces;

  { Parse optional line number }
  if (line_pos < line_len) and is_digit(line_buf[line_pos]) then
  begin
    tok_line_num := parse_integer;
    skip_spaces
  end;

  { Tokenize remaining }
  while line_pos < line_len do
  begin
    skip_spaces;
    if line_pos >= line_len then
    begin
      { done }
    end
    else
    begin
      ch := line_buf[line_pos];

      { Try keyword match first }
      ki := try_keyword;
      if ki >= 0 then
      begin
        emit(FIRST_KEYWORD + ki);
        { REM: rest of line is a string token }
        if ki = 14 then
        begin
          emit(TOK_STR);
          n := line_len - line_pos;
          emit(n);
          while line_pos < line_len do
          begin
            emit(ord(line_buf[line_pos]));
            line_pos := line_pos + 1
          end
        end
      end
      { String literal }
      else if ch = '"' then
      begin
        line_pos := line_pos + 1;
        emit(TOK_STR);
        n := tok_len;
        emit(0);  { placeholder for length }
        ki := 0;
        while (line_pos < line_len) and (line_buf[line_pos] <> '"') do
        begin
          emit(ord(line_buf[line_pos]));
          line_pos := line_pos + 1;
          ki := ki + 1
        end;
        tok_buf[n] := ki;  { patch length }
        if (line_pos < line_len) and (line_buf[line_pos] = '"') then
          line_pos := line_pos + 1
      end
      { Integer literal }
      else if is_digit(ch) then
      begin
        n := parse_integer;
        emit(TOK_INT);
        emit((n div 65536) mod 256);
        emit((n div 256) mod 256);
        emit(n mod 256)
      end
      { Variable (single letter A-Z) }
      else if is_letter(ch) then
      begin
        emit(TOK_VAR_A + ord(upcase(ch)) - ord('A'));
        line_pos := line_pos + 1
      end
      { Two-char operators }
      else if (ch = '<') and (line_pos + 1 < line_len) and (line_buf[line_pos + 1] = '>') then
      begin emit(TOK_PLUS + 5); line_pos := line_pos + 2 end
      else if (ch = '<') and (line_pos + 1 < line_len) and (line_buf[line_pos + 1] = '=') then
      begin emit(TOK_PLUS + 7); line_pos := line_pos + 2 end
      else if (ch = '>') and (line_pos + 1 < line_len) and (line_buf[line_pos + 1] = '=') then
      begin emit(TOK_GE); line_pos := line_pos + 2 end
      { Single-char operators }
      else if ch = '+' then begin emit(TOK_PLUS);     line_pos := line_pos + 1 end
      else if ch = '-' then begin emit(TOK_PLUS + 1); line_pos := line_pos + 1 end
      else if ch = '*' then begin emit(TOK_PLUS + 2); line_pos := line_pos + 1 end
      else if ch = '/' then begin emit(TOK_PLUS + 3); line_pos := line_pos + 1 end
      else if ch = '=' then begin emit(TOK_PLUS + 4); line_pos := line_pos + 1 end
      else if ch = '<' then begin emit(TOK_PLUS + 6); line_pos := line_pos + 1 end
      else if ch = '>' then begin emit(TOK_PLUS + 8); line_pos := line_pos + 1 end
      { Delimiters }
      else if ch = '(' then begin emit(176); line_pos := line_pos + 1 end
      else if ch = ')' then begin emit(177); line_pos := line_pos + 1 end
      else if ch = ',' then begin emit(178); line_pos := line_pos + 1 end
      else if ch = ';' then begin emit(179); line_pos := line_pos + 1 end
      { Unknown character: skip }
      else
        line_pos := line_pos + 1
    end
  end;

  emit(0)  { TOK_EOL }
end;

