program BasicStore;
{ COR24 BASIC v1 — Program store. Packed sorted buffer of tokenized lines.
  Each line: [line_hi][line_lo][len][tok0..tokN] where line# = hi*256+lo.
  Lines sorted by line number. Insert/delete shifts subsequent bytes. }
const
  PS=4096; { program store size in bytes }
var
  pg: array[0..4095] of char; { program store }
  pe: integer; { end pointer (next free byte) }

procedure store_init;
begin pe := 0 end;

function pg_line(p: integer): integer;
{ Read line number at offset p }
begin pg_line := ord(pg[p])*256 + ord(pg[p+1]) end;

function pg_len(p: integer): integer;
{ Read token length at offset p (after 2-byte line number) }
begin pg_len := ord(pg[p+2]) end;

function pg_size(p: integer): integer;
{ Total bytes for entry at p: 2 (line#) + 1 (len) + len (tokens) }
begin pg_size := 3 + ord(pg[p+2]) end;

function store_find(ln: integer): integer;
{ Find line with number ln. Returns offset or -1. }
var p, n: integer;
begin
  p := 0;
  while p < pe do
  begin
    n := pg_line(p);
    if n = ln then begin store_find := p; exit end;
    if n > ln then begin store_find := -1; exit end;
    p := p + pg_size(p)
  end;
  store_find := -1
end;

function store_find_insert(ln: integer): integer;
{ Find insertion point for line ln. Returns offset where it should go. }
var p: integer;
begin
  p := 0;
  while p < pe do
  begin
    if pg_line(p) >= ln then begin store_find_insert := p; exit end;
    p := p + pg_size(p)
  end;
  store_find_insert := pe
end;

procedure store_delete(ln: integer);
{ Delete line with number ln. No-op if not found. }
var p, sz, i: integer;
begin
  p := store_find(ln);
  if p >= 0 then
  begin
    sz := pg_size(p);
    i := p;
    while i + sz < pe do
    begin pg[i] := pg[i + sz]; i := i + 1 end;
    pe := pe - sz
  end
end;

procedure store_insert(ln: integer; var tb: array[0..127] of integer; tlen: integer);
{ Insert tokenized line. Replaces existing line with same number. }
var p, sz, i, need: integer;
begin
  store_delete(ln);
  need := 3 + tlen; { 2 bytes line# + 1 byte len + tokens }
  if pe + need > PS then exit; { out of memory }
  p := store_find_insert(ln);
  { Shift bytes right to make room }
  i := pe - 1;
  while i >= p do
  begin pg[i + need] := pg[i]; i := i - 1 end;
  { Write entry }
  pg[p] := chr(ln div 256);
  pg[p+1] := chr(ln mod 256);
  pg[p+2] := chr(tlen);
  i := 0;
  while i < tlen do
  begin pg[p + 3 + i] := chr(tb[i]); i := i + 1 end;
  pe := pe + need
end;

function store_next(p: integer): integer;
{ Advance past current entry. Returns next offset or pe if at end. }
begin store_next := p + pg_size(p) end;

function store_count: integer;
{ Count stored lines }
var p, n: integer;
begin
  p := 0; n := 0;
  while p < pe do begin n := n + 1; p := p + pg_size(p) end;
  store_count := n
end;

{ --- Self-test --- }
var
  tb: array[0..127] of integer;
  f, p: integer;

procedure ck(ok: boolean; id: integer);
begin if ok then write('P') else begin write('F'); f := f+1 end; writeln(id) end;

begin
  store_init; f := 0;
  { Insert line 20 with 3 tokens: [129, 225, 0] (PRINT, STR, EOL) }
  tb[0] := 129; tb[1] := 225; tb[2] := 0;
  store_insert(20, tb, 3);
  ck(store_count = 1, 1);
  ck(store_find(20) = 0, 2);
  ck(pg_line(0) = 20, 3);
  ck(pg_len(0) = 3, 4);
  { Insert line 10 (should go before line 20) }
  tb[0] := 141; tb[1] := 0; { END, EOL }
  store_insert(10, tb, 2);
  ck(store_count = 2, 5);
  ck(store_find(10) = 0, 6);
  p := store_find(20);
  ck(p = 5, 7); { 2+1+2 = 5 bytes for line 10 entry }
  ck(pg_line(p) = 20, 8);
  { Insert line 30 at end }
  tb[0] := 140; tb[1] := 0; { STOP, EOL }
  store_insert(30, tb, 2);
  ck(store_count = 3, 9);
  { Delete line 20 }
  store_delete(20);
  ck(store_count = 2, 10);
  ck(store_find(20) = -1, 11);
  ck(store_find(10) = 0, 12);
  ck(store_find(30) >= 0, 13);
  { Replace line 10 }
  tb[0] := 128; tb[1] := 0; { LET, EOL }
  store_insert(10, tb, 2);
  ck(store_count = 2, 14);
  p := store_find(10);
  ck(ord(pg[p+3]) = 128, 15); { first token is LET }
  { store_next traversal }
  p := 0;
  p := store_next(p); { skip line 10 }
  ck(pg_line(p) = 30, 16);
  writeln(f)
end.

