program BasicExpr;
{ COR24 BASIC v1 — Expression parser + variable table.
  Precedence climbing: comparisons < add/sub < mul/div < unary.
  Reads tokens from eb[] via ep cursor. Returns integer result. }
const
  FK=128; TP=160; TG=169; VA=192; TI=224; TS=225;
var
  eb: array[0..127] of integer; { expression token buffer }
  ep: integer; { cursor into eb }
  vars: array[0..25] of integer; { A-Z variables }
  err: integer; { 0=ok, nonzero=error code }

procedure vars_clear;
var i: integer;
begin i:=0; while i<26 do begin vars[i]:=0; i:=i+1 end end;

function cur: integer;
{ Current token without advancing }
begin cur := eb[ep] end;

procedure adv;
{ Advance cursor }
begin ep := ep+1 end;

function expect(tok: integer): boolean;
{ Check current token matches, advance if so }
begin
  if eb[ep] = tok then begin adv; expect := true end
  else begin err := 1; expect := false end
end;

function expr: integer; { forward-declared via mutual recursion trick }

function parse_primary: integer;
var v, idx: integer;
begin
  v := 0;
  if cur = TI then begin
    adv; v := eb[ep]*65536 + eb[ep+1]*256 + eb[ep+2]; ep := ep+3
  end
  else if (cur >= VA) and (cur <= VA+25) then begin
    v := vars[cur - VA]; adv
  end
  else if cur = 176 then begin { ( }
    adv; v := expr;
    if err = 0 then
      if not expect(177) then v := 0 { ) }
  end
  else if cur = FK+21 then begin { PEEK }
    adv;
    if expect(176) then begin v := peek(expr);
      if err = 0 then
        if not expect(177) then v := 0
    end
  end
  else if cur = FK+23 then begin { ABS }
    adv;
    if expect(176) then begin v := expr;
      if err = 0 then begin
        if v < 0 then v := 0 - v;
        if not expect(177) then v := 0
      end
    end
  end
  else err := 1;
  parse_primary := v
end;

function parse_unary: integer;
var v: integer;
begin
  if cur = TP+1 then begin adv; v := 0 - parse_unary end { - }
  else if cur = TP then begin adv; v := parse_unary end { + }
  else v := parse_primary;
  parse_unary := v
end;

function parse_term: integer;
var v, op, r: integer;
begin
  v := parse_unary;
  while (err = 0) and ((cur = TP+2) or (cur = TP+3)) do begin
    op := cur; adv; r := parse_unary;
    if op = TP+2 then v := v * r
    else if r <> 0 then v := v div r
    else err := 5 { division by zero }
  end;
  parse_term := v
end;

function parse_addition: integer;
var v, op, r: integer;
begin
  v := parse_term;
  while (err = 0) and ((cur = TP) or (cur = TP+1)) do begin
    op := cur; adv; r := parse_term;
    if op = TP then v := v + r else v := v - r
  end;
  parse_addition := v
end;

function expr: integer;
var v, op, r: integer; b: boolean;
begin
  v := parse_addition;
  while (err = 0) and (cur >= TP+4) and (cur <= TG) do begin
    op := cur; adv; r := parse_addition;
    b := false;
    if op = TP+4 then b := (v = r)     { = }
    else if op = TP+5 then b := (v <> r) { <> }
    else if op = TP+6 then b := (v < r)  { < }
    else if op = TP+7 then b := (v <= r) { <= }
    else if op = TP+8 then b := (v > r)  { > }
    else if op = TG then b := (v >= r);  { >= }
    if b then v := 1 else v := 0
  end;
  expr := v
end;

