var tf: integer;
procedure ck(ok:boolean;id:integer);
begin if ok then write('P')else begin write('F');tf:=tf+1 end;writeln(id)end;

procedure set_int(pos, val: integer);
{ Write integer literal at eb[pos]: TI, hi, mid, lo }
begin
  eb[pos] := TI;
  eb[pos+1] := (val div 65536) mod 256;
  eb[pos+2] := (val div 256) mod 256;
  eb[pos+3] := val mod 256
end;

