  set_int(0, 10); eb[4] := TP+1; set_int(5, 3); eb[9] := 0; ep := 0; err := 0;
  ck(expr = 7, 3);
  { Test 4: 4 * 5 }
  set_int(0, 4); eb[4] := TP+2; set_int(5, 5); eb[9] := 0; ep := 0; err := 0;
  ck(expr = 20, 4);
