  eb[11]:=TP+2; set_int(12,4); eb[16]:=0; ep:=0; err:=0;
  ck(expr=20, 11);
  { Test 12: division by zero }
  set_int(0,5); eb[4]:=TP+3; set_int(5,0); eb[9]:=0; ep:=0; err:=0;
  ck((expr=0)and(err=5), 12);
  writeln(tf)
end.

