function cur: integer;
{ Current token without advancing }
begin cur := eb[ep] end;

procedure adv;
{ Advance cursor }
begin ep := ep+1 end;

function expect(tok: integer): boolean;
{ Check current token matches, advance if so }
begin
  if eb[ep] = tok then begin adv; expect := true end
  else begin err := 1; expect := false end
end;

function expr: integer; { forward-declared via mutual recursion trick }

function parse_primary: integer;
var v, idx: integer;
