    v := vars[cur - VA]; adv
  end
  else if cur = 176 then begin { ( }
    adv; v := expr;
    if err = 0 then
      if not expect(177) then v := 0 { ) }
  end
  else if cur = FK+21 then begin { PEEK }
    adv;
    if expect(176) then begin v := peek(expr);
      if err = 0 then
