var vi: integer;
begin
  if (eb[ep] >= VA) and (eb[ep] <= VA+25) then begin
    vi := eb[ep] - VA; ep := ep + 1;
    if eb[ep] = TP+4 then begin ep := ep + 1; p_expr(4); vars[vi] := ev end
