  ck(err=0, 4);
  { Test 5: PRINT 2+3 -> prints "5\n" }
  si(0,2); eb[4]:=TP; si(5,3); eb[9]:=0;
  ep:=0; err:=0; do_print;
  ck(err=0, 5);
  { Test 6: PRINT "X=";A -> prints "X=7\n" }
  eb[0]:=TS; eb[1]:=2; eb[2]:=88; eb[3]:=61; eb[4]:=179;
  eb[5]:=VA; eb[6]:=0; ep:=0; err:=0; do_print;
