    else if eb[ep] = 178 then begin ep := ep + 1; writechar(chr(9)) end { , tab }
    else begin writeln(''); dn := 1 end
  end
end;

procedure do_let;
{ LET var = expr  (LET keyword already consumed by dispatch) }
var vi: integer;
begin
  if (eb[ep] >= VA) and (eb[ep] <= VA+25) then begin
    vi := eb[ep] - VA; ep := ep + 1;
