  if(err=0)and(tb[ep]=178)then begin ep:=ep+1;p_expr(4);if err=0 then poke(addr,ev) end
  else err:=1 end;

{ --- Read line from UART --- }
procedure read_line;
var ch:char;
begin
  ll:=0;
  readln(ch);
  while (ch <> chr(10)) and (ch <> chr(13)) and (ch <> chr(4)) and (ll < 80) do
  begin lb[ll]:=ch; ll:=ll+1; readln(ch) end
end;

{ --- Statement dispatch --- }
procedure dispatch;
var t:integer;
begin
  ep:=0; err:=0;
  t:=tb[ep];
  if t=0 then begin end { empty line }
  else if t=FK then begin ep:=ep+1; do_let end { LET }
  else if t=FK+1 then begin ep:=ep+1; do_print end { PRINT }
  else if t=FK+22 then begin ep:=ep+1; do_poke end { POKE }
  else if t=FK+20 then running:=0 { BYE }
  else if(t>=VA)and(t<=VA+25)then do_let { implicit LET }
  else err:=2; { WHAT? }
  if err<>0 then begin write('?ERR '); writeln(err) end
end;

